import React from 'react';

function App() {
    return (
        <div style={{
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            height: '100vh',
            flexDirection: 'column',
            fontFamily: 'Arial, sans-serif'
        }}>
            <h1>🎉 SCRAS Frontend is Working!</h1>
            <p>If you see this, React is rendering correctly.</p>
            <p>Now we can add the full app.</p>
        </div>
    );
}

export default App;
